@startuml

package "xxx" {
  interface Shape {
    void draw()
  }

  class Circle {
    void draw()
  }

  class Rectangle {
    void draw()
  }

  class Square {
    void draw()
  }

  Circle .up.|> Shape : implement
  Rectangle .up.|> Shape : implement
  Square .up.|> Shape : implement
}

class ShapeFactory {
  Shape getShape()
}

class FactoryPatternDemo {
  void main()
}

FactoryPatternDemo -up-> ShapeFactory : ask
ShapeFactory -left-> Shape : create

@enduml
